import network, socket, uhashlib, ubinascii, ujson, machine, time, gc, _thread

# ---------- CONFIG ----------
WIFI_SSID = 'YOUR_SSID'
WIFI_PSK  = 'YOUR_PASSWORD'
PORT      = 80
LED_PIN   = 2            # onboard LED for ESP32 (adjust if needed)
# ----------------------------

led = machine.Pin(LED_PIN, machine.Pin.OUT)

MAGIC_GUID = b'258EAFA5-E914-47DA-95CA-C5AB0DC85B11'

def connect_wifi(ssid, psk):
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        wlan.connect(ssid, psk)
        while not wlan.isconnected():
            time.sleep(0.5)
    print('Connected, IP:', wlan.ifconfig()[0])
    return wlan

def websocket_accept(key):
    sha1 = uhashlib.sha1(key + MAGIC_GUID).digest()
    return ubinascii.b2a_base64(sha1).strip()

def send_ws_text(conn, msg):
    if isinstance(msg, str):
        msg = msg.encode()
    length = len(msg)
    header = bytearray()
    header.append(0x81)  # FIN + text frame
    if length <= 125:
        header.append(length)
    elif length <= 65535:
        header.append(126)
        header.extend(length.to_bytes(2, 'big'))
    else:
        header.append(127)
        header.extend(length.to_bytes(8, 'big'))
    conn.send(header + msg)

def recv_exact(conn, n):
    data = b''
    while len(data) < n:
        chunk = conn.recv(n - len(data))
        if not chunk:
            raise OSError('connection closed')
        data += chunk
    return data

def process_command(data):
    try:
        obj = ujson.loads(data)
        act = obj.get('action')
        if act == 'turn_on':
            led.on()
            return ujson.dumps({'status':'on'})
        elif act == 'turn_off':
            led.off()
            return ujson.dumps({'status':'off'})
        else:
            return ujson.dumps({'error':'unknown action'})
    except Exception as e:
        return ujson.dumps({'error':str(e)})

def websocket_session(conn, addr):
    try:
        # ---- Handshake ----
        req = b''
        while b'\r\n\r\n' not in req:
            chunk = conn.recv(1024)
            if not chunk:
                conn.close()
                return
            req += chunk
        headers = req.decode().split('\r\n')
        key = None
        for h in headers:
            if h.lower().startswith('sec-websocket-key'):
                key = h.split(':',1)[1].strip().encode()
                break
        if not key:
            conn.close()
            return
        accept = websocket_accept(key).decode()
        resp = ('HTTP/1.1 101 Switching Protocols\r\n'
                'Upgrade: websocket\r\n'
                'Connection: Upgrade\r\n'
                'Sec-WebSocket-Accept: {}\r\n\r\n').format(accept)
        conn.send(resp.encode())

        # ---- Data Frames ----
        while True:
            hdr = recv_exact(conn, 2)
            b1, b2 = hdr
            fin = b1 & 0x80
            opcode = b1 & 0x0F
            masked = b2 & 0x80
            length = b2 & 0x7F

            if opcode == 0x8:   # connection close
                break

            if length == 126:
                length = int.from_bytes(recv_exact(conn, 2), 'big')
            elif length == 127:
                length = int.from_bytes(recv_exact(conn, 8), 'big')

            mask = recv_exact(conn, 4) if masked else b''
            payload = recv_exact(conn, length)

            if masked:
                payload = bytes(b ^ mask[i % 4] for i, b in enumerate(payload))

            try:
                txt = payload.decode()
            except:
                continue

            reply = process_command(txt)
            send_ws_text(conn, reply)

    except Exception as e:
        pass
    finally:
        try:
            conn.close()
        except:
            pass
        gc.collect()

def server_loop():
    addr_info = socket.getaddrinfo('0.0.0.0', PORT)[0][-1]
    srv = socket.socket()
    srv.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    srv.bind(addr_info)
    srv.listen(2)
    print('WebSocket server listening on port', PORT)
    while True:
        try:
            conn, addr = srv.accept()
            _thread.start_new_thread(websocket_session, (conn, addr))
        except Exception as e:
            pass

def main():
    connect_wifi(WIFI_SSID, WIFI_PSK)
    server_loop()

if __name__ == '__main__':
    main()